		if windowSeconds == 0 && w.WindowMinutes > 0 {
			windowSeconds = w.WindowMinutes * 60
		}
		if resetAt == "" {
			if w.ResetsAt != "" {
				resetAt = w.ResetsAt
			} else if w.ResetsAtUnix > 0 {
				resetAt = time.Unix(w.ResetsAtUnix, 0).UTC().Format(time.RFC3339)
			}
